window.addEventListener('load', function() {
  var win = window.open('https://example.com/tab2', '_blank', 'width=200,height=100');
  win.postMessage('Hello, Tab 2!', '*');
});

// Tab 2
window.addEventListener('message', function(event) {
  if (event.origin === 'https://example.com') {
    console.log(event.data); // prints: Hello, Tab 2!
  }
});
```

