const mongoose = require('mongoose');
const jwt = require('jsonwebtoken');

const userSchema = new mongoose.Schema({
  name: String,
  email: String,
  password: String,
  tokens: [{ type: String, expires: Date }]
});

userSchema.methods.generateToken = function() {
  const token = jwt.sign({ _id: this._id }, process.env.SECRET_KEY, { expiresIn: '1h' });
  this.tokens.push({ token, expires: new Date(Date.now() + 3600000) });
  return token;
};

userSchema.methods.revalidateToken = async function() {
  const user = await this.findOne({ _id: this._id });
  if (!user) {
    throw new Error('User not found');
  }
  const token = user.tokens[0];
  if (!token || token.expires < new Date()) {
    const newToken = await this.generateToken();
    return newToken;
  }
  return token.token;
};

module.exports = mongoose.model('User', userSchema);
```

